"""Batch greet candidates on Boss直聘 recommend page.

Automates the "打招呼" flow on the recommend page:
1. Switch to the specified job posting
2. Extract candidate info from cards
3. Prioritize big-company candidates
4. Click "打招呼" on each with rate-limited delays
5. Scroll to load more candidates
6. Track and report results
"""

import asyncio
import json
import random
import sys
import time
from datetime import datetime
from pathlib import Path

# Add project root to path
sys.path.insert(0, str(Path(__file__).parent.parent))

from src.core.browser import get_browser_manager
from src.utils.config import get_config

# --- Configuration ---
TARGET_JOB_VALUE = "04ebe0c3c86affd603J82tm_EVZY"  # Android高级开发工程师
TARGET_JOB_NAME = "Android高级开发工程师"
MIN_DELAY = 8  # seconds between greetings (Boss自身也有频率限制)
MAX_DELAY = 15
MAX_GREETS = 200  # safety cap
SCROLL_WAIT = 3  # seconds to wait after scrolling
PREFERRED_YEARS_MIN = 3
PREFERRED_YEARS_MAX = 5

# Big company keywords for prioritization
BIG_COMPANIES = {
    "腾讯", "阿里", "字节", "百度", "美团", "京东", "拼多多", "网易",
    "滴滴", "快手", "小红书", "华为", "大疆", "小米", "OPPO", "vivo",
    "联想", "360", "搜狐", "新浪", "微博", "携程", "去哪儿", "58同城",
    "蚂蚁", "饿了么", "高德", "优酷", "爱奇艺", "bilibili", "B站",
    "微信", "抖音", "头条", "淘宝", "天猫", "支付宝", "钉钉",
    "shopee", "Shopee", "字节跳动", "阿里巴巴", "Tencent", "Baidu",
    "Alibaba", "ByteDance", "Meituan", "JD", "Xiaomi", "Huawei",
    "知乎", "陌陌", "探探", "Soul", "YY", "虎牙", "斗鱼",
    "猿辅导", "作业帮", "好未来", "新东方",
    "顺丰", "菜鸟", "中通", "韵达",
    "商汤", "旷视", "科大讯飞", "寒武纪",
}


def _parse_years(info_text: str) -> int:
    """Extract years of experience from info text like '30岁 9年 本科'."""
    import re
    m = re.search(r'(\d+)年', info_text)
    return int(m.group(1)) if m else 0


def _is_big_company(company: str) -> bool:
    """Check if company name matches any big company keywords."""
    for kw in BIG_COMPANIES:
        if kw in company:
            return True
    return False


def _score_candidate(info: dict) -> int:
    """Score a candidate for prioritization.
    Higher score = higher priority.
    """
    score = 50  # base score

    years = info.get('years', 0)
    company = info.get('company', '')

    # Experience match (3-5 years preferred)
    if PREFERRED_YEARS_MIN <= years <= PREFERRED_YEARS_MAX:
        score += 30
    elif years > 0:
        # Some bonus for close matches
        diff = min(abs(years - PREFERRED_YEARS_MIN), abs(years - PREFERRED_YEARS_MAX))
        score += max(0, 20 - diff * 5)

    # Big company bonus
    if _is_big_company(company):
        score += 20

    # Active status bonus
    active = info.get('active', '')
    if '刚刚' in active or '今日' in active:
        score += 10
    elif '3日' in active:
        score += 5

    # Ready to join bonus
    if '离职' in info.get('job_status', ''):
        score += 5
    elif '月内到岗' in info.get('job_status', ''):
        score += 3

    return score


async def switch_to_job(frame, job_value: str, job_name: str) -> bool:
    """Switch to the target job posting in the recommend page."""
    # Click the job selector to open dropdown
    label = await frame.query_selector('.job-selecter-wrap .ui-dropmenu-label')
    if not label:
        print("ERROR: Job selector label not found")
        return False

    current_text = await label.inner_text()
    if job_name in current_text:
        print(f"Already on job: {current_text.strip()}")
        return True

    await label.click()
    await asyncio.sleep(1)

    # Click the target job item
    result = await frame.evaluate("""
        (targetValue) => {
            const items = document.querySelectorAll('.job-item');
            for (const item of items) {
                if (item.getAttribute('value') === targetValue) {
                    item.click();
                    return true;
                }
            }
            return false;
        }
    """, job_value)

    if result:
        await asyncio.sleep(3)  # Wait for candidate list to refresh
        new_label = await frame.query_selector('.job-selecter-wrap .ui-dropmenu-label')
        new_text = await new_label.inner_text() if new_label else "?"
        print(f"Switched to job: {new_text.strip()}")
        return True
    else:
        print(f"ERROR: Could not find job with value {job_value}")
        return False


async def extract_candidates(frame) -> list:
    """Extract candidate info from visible cards."""
    return await frame.evaluate("""
        () => {
            const cards = document.querySelectorAll('.card-item');
            const results = [];
            for (const card of cards) {
                const inner = card.querySelector('.card-inner');
                if (!inner) continue;

                const nameEl = card.querySelector('.name');
                const name = nameEl ? nameEl.innerText.trim() : '';
                if (!name) continue;

                const baseInfo = card.querySelector('.base-info');
                const info = baseInfo ? baseInfo.innerText.trim() : '';

                const activeEl = card.querySelector('.active-text');
                const active = activeEl ? activeEl.innerText.trim() : '';

                const expectEl = card.querySelector('.expect-wrap');
                const expect = expectEl ? expectEl.innerText.trim() : '';

                const salaryEl = card.querySelector('.salary-wrap span');
                const salary = salaryEl ? salaryEl.innerText.trim() : '';

                const greetBtn = card.querySelector('button.btn.btn-greet');
                const canGreet = !!greetBtn && !greetBtn.disabled;

                const geekId = inner.getAttribute('data-geek') ||
                               inner.getAttribute('data-geekid') || '';

                results.push({
                    name, info, active, expect, salary,
                    canGreet, geekId
                });
            }
            return results;
        }
    """)


async def click_greet_by_geek_id(frame, geek_id: str) -> str:
    """Click the greet button for a specific candidate by geek ID.
    Returns: 'ok', 'no_button', 'dialog', 'error'
    """
    result = await frame.evaluate("""
        (geekId) => {
            const cards = document.querySelectorAll('.card-item');
            for (const card of cards) {
                const inner = card.querySelector('.card-inner');
                if (!inner) continue;
                const id = inner.getAttribute('data-geek') ||
                           inner.getAttribute('data-geekid') || '';
                if (id === geekId) {
                    const btn = card.querySelector('button.btn.btn-greet');
                    if (btn && !btn.disabled) {
                        btn.click();
                        return 'clicked';
                    }
                    return 'no_button';
                }
            }
            return 'not_found';
        }
    """, geek_id)

    if result != 'clicked':
        return result

    # Wait and check for dialogs or quota warnings
    await asyncio.sleep(2)

    # Check for any popup dialogs on the MAIN page (parent of iframe)
    page = frame.page
    dialog_check = await page.evaluate("""
        () => {
            // Check for quota exhaustion
            const body = document.body.innerText;
            if (body.includes('今日沟通次数已用完') ||
                body.includes('沟通次数已达上限') ||
                body.includes('今日联系人数已满')) {
                return 'quota_exhausted';
            }

            // Check for popup dialogs
            const dialogs = document.querySelectorAll('.dialog-wrap.active, .boss-popup');
            for (const d of dialogs) {
                const text = d.innerText || '';
                if (text.includes('升级') || text.includes('会员') || text.includes('购买')) {
                    // Close it
                    const closeBtn = d.querySelector('.boss-popup__close, .iboss-close, .close-btn');
                    if (closeBtn) closeBtn.click();
                    return 'purchase_dialog';
                }
            }

            return 'ok';
        }
    """)

    return dialog_check


async def scroll_and_load_more(frame) -> int:
    """Scroll down to load more candidates. Returns new candidate count."""
    before_count = await frame.evaluate("document.querySelectorAll('.card-item').length")

    await frame.evaluate("window.scrollTo(0, document.body.scrollHeight)")
    await asyncio.sleep(SCROLL_WAIT)

    after_count = await frame.evaluate("document.querySelectorAll('.card-item').length")
    return after_count - before_count


async def batch_greet():
    """Main batch greeting function."""
    bm = get_browser_manager()
